def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    min_distance = np.inf
    next_node = None

    for node in unvisited_nodes:
        if node == current_node:
            continue

        dist_from_current = distance_matrix[current_node][node]
        dist_from_depot = distance_matrix[depot_node][node]

        closest_truck_distance = np.inf
        for truck_node in truck_nodes:
            truck_distance = distance_matrix[truck_node][node]
            if truck_distance < closest_truck_distance:
                closest_truck_distance = truck_distance

        total_distance = dist_from_current + dist_from_depot - 0.5*closest_truck_distance

        if total_distance < min_distance:
            min_distance = total_distance
            next_node = node

    return next_node

