import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):

    if len(unvisited_nodes) == 0:
        return depot_node

    min_distance = np.inf
    next_node = None

    for node in unvisited_nodes:
        truck_distances = []
        for truck_node in truck_nodes:
            distance = distance_matrix[current_node][truck_node] + distance_matrix[truck_node][node]
            truck_distances.append(distance)

        total_distance = sum(truck_distances)

        if total_distance < min_distance:
            min_distance = total_distance
            next_node = node

    return next_node
